import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface ColumnCount {
  column: string;
  count: number;
}

interface KanbanData {
  projectName: string;
  columnCounts: ColumnCount[];
  totalTasks: number;
}

export default function Widget() {
  const kanbanData = response.data as KanbanData;
  const { projectName, columnCounts, totalTasks } = kanbanData;
  const chartData = columnCounts.map((column) => column.count);
  const columnNames = columnCounts.map((column) => column.column);

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#1F1F1F' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#4A90E2', mb: 1 }}>
              {projectName}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ color: '#FFFFFF' }}>
              Total Tasks: {totalTasks}
            </Typography>
          </Box>

          <BarChart
            height={150}
            series={[
              {
                data: chartData,
                color: '#50E3C2',
              },
            ]}
            xAxis={[
              {
                data: columnNames,
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#FFFFFF',
                },
              },
            ]}
            yAxis={[
              {
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#FFFFFF',
                },
              },
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />

          <Stack direction="row" spacing={0.5}>
            {columnCounts.map((column, index) => (
              <Chip
                key={index}
                label={`${column.column}: ${column.count}`}
                sx={{ fontSize: '10px', px: 1, py: 0.5, color: '#FFFFFF', bgcolor: '#333333' }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
